class Node:
    def __init__(self, name):
        self.name = name
        self.connections = []

class Network:
    def __init__(self):
        self.nodes = {}

    def add_node(self, name):
        self.nodes[name] = Node(name)

    def add_connection(self, node1, node2):
        if node1 in self.nodes and node2 in self.nodes:
            self.nodes[node1].connections.append(node2)
            self.nodes[node2].connections.append(node1)
        else:
            print("One or both nodes do not exist in the network.")

    def print_network(self):
        for node in self.nodes.values():
            print(f"Node {node.name} is connected to: {node.connections}")

    def simulate_data_transmission(self, node1, node2, data):
        if node1 in self.nodes and node2 in self.nodes:
            if node1!= node2:
                print(f"Data '{data}' is being transmitted from {node1} to {node2}")
                return True
            else:
                print(f"Cannot transmit data from {node1} to itself.")
                return False
        else:
            print("One or both nodes do not exist in the network.")
            return False

    def draw_network(self):
        G = nx.Graph()
        for node in self.nodes.values():
            G.add_node(node.name)
