import random
import time

class Exam:
    def __init__(self, name):
        self.name = name
        self.questions = []
        self.answers = []
        self.score = 0

    def add_question(self):
        question = input("Enter question: ")
        options = input("Enter options (comma separated): ").split(',')
        correct_answer = input("Enter correct answer: ")
        self.questions.append(question)
        self.answers.append(correct_answer)
        print(f"Question added: {question}")

    def display_questions(self):
        for i, question in enumerate(self.questions):
            print(f"{i+1}. {question}")

    def administer_exam(self):
        print("Exam started. Please answer the questions.")
        for i, question in enumerate(self.questions):
            print(f"\n{i+1}. {question}")
            options = input("Enter your answer (A, B, C, D): ").upper()
            if options == self.answers[i]:
                self.score += 1
                print("Correct answer!")
            else:
                print("Incorrect answer.")
        print(f"\nExam finished. Your score is {self.score}/{len(self.questions)}")

    def display_results(self):
        print(f"Exam results: {self.name}")
        print(f"Score: {self.score}/{len(self.questions)}")

def main():
    exam_name = input("Enter exam name: ")
    exam = Exam(exam_name)
    while True:
        print("\nOptions:")
        print("1. Add question")
        print("2. Display questions")
        print("3. Administer exam")
        print("4. Display results")
        print("5. Quit")
        choice = input("Enter choice: ")
        if choice == "1":
            exam.add_question()
        elif choice == "2":
            exam.display_questions()
        elif choice == "3":
            exam.administer_exam()
        elif choice == "4":
            exam.display_results()
        elif choice == "5":
            break
        else:
            print("Invalid choice. Please try again.")

if __name__ == "__main__":
    main()
